from collections import defaultdict

class Solution(object):
    def distance(self, nums):
        n = len(nums)
        groups = defaultdict(list)
        for i, v in enumerate(nums):
            groups[v].append(i)

        arr = [0] * n
        for indices in groups.values():
            m = len(indices)
            if m == 1:
                continue
            prefix = [0] * (m + 1)
            for k in range(m):
                prefix[k + 1] = prefix[k] + indices[k]

            for k, idx in enumerate(indices):
                # Sum of distances to elements to the right
                right = (prefix[m] - prefix[k + 1]) - idx * (m - k - 1)
                # Sum of distances to elements to the left
                left = idx * k - prefix[k]
                arr[idx] = left + right

        return arr
